// Extract Polymarket sports markets and their current prices
const markets = $input.all();
const results = [];

for (const item of markets) {
  const m = item.json;
  const question = m.question || m.title || '';

  let outcomePrices = m.outcomePrices || [];
  if (typeof outcomePrices === 'string') {
    try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
  }

  let outcomes = m.outcomes || [];
  if (typeof outcomes === 'string') {
    try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
  }

  let clobTokenIds = m.clobTokenIds || [];
  if (typeof clobTokenIds === 'string') {
    try { clobTokenIds = JSON.parse(clobTokenIds); } catch(e) { clobTokenIds = []; }
  }

  const yesPrice = Number(outcomePrices[0] || 0);

  // Extract team names from question (heuristic: look for 'vs' or 'win' patterns)
  const teamMatch = question.match(/will\s+(?:the\s+)?(.+?)\s+(?:win|beat|defeat)/i)
    || question.match(/(.+?)\s+vs?\.?\s+(.+)/i);

  const teamName = teamMatch ? teamMatch[1].trim() : question.substring(0, 30);

  results.push({
    question,
    conditionId: m.conditionId || '',
    slug: m.slug || '',
    yesPrice,
    outcomes,
    tokenId: clobTokenIds[0] || '',
    teamName,
    volume: Number(m.volume || 0)
  });
}

return [{
  json: {
    polymarketGames: results,
    gameCount: results.length
  }
}];

// Match games between Polymarket and sportsbooks, calculate line differences
const oddsRaw = $input.first().json;
const polyData = $('Extract Market Prices').first().json;
const polyGames = polyData.polymarketGames || [];
const staticData = $getWorkflowStaticData('global');

// Parse sportsbook odds (The Odds API returns array of games)
const sportsGames = Array.isArray(oddsRaw) ? oddsRaw : (oddsRaw.data || [oddsRaw]);

// Helper: convert American moneyline to implied probability
function moneylineToProbability(ml) {
  ml = Number(ml);
  if (ml > 0) return 100 / (ml + 100);
  if (ml < 0) return Math.abs(ml) / (Math.abs(ml) + 100);
  return 0.5;
}

// Helper: fuzzy team name matching
function teamMatch(polyName, bookName) {
  const pLower = polyName.toLowerCase().replace(/[^a-z]/g, '');
  const bLower = bookName.toLowerCase().replace(/[^a-z]/g, '');
  return pLower.includes(bLower) || bLower.includes(pLower) || pLower === bLower;
}

const matches = [];

for (const polyGame of polyGames) {
  for (const sportsGame of sportsGames) {
    const homeTeam = sportsGame.home_team || '';
    const awayTeam = sportsGame.away_team || '';

    if (teamMatch(polyGame.teamName, homeTeam) || teamMatch(polyGame.teamName, awayTeam)) {
      // Get average odds across bookmakers
      const bookmakers = sportsGame.bookmakers || [];
      let avgOdds = 0.5;
      let bookCount = 0;

      for (const book of bookmakers) {
        const h2h = (book.markets || []).find(m => m.key === 'h2h');
        if (h2h && h2h.outcomes) {
          // Find matching team outcome
          const matchingOutcome = h2h.outcomes.find(o =>
            teamMatch(polyGame.teamName, o.name)
          );
          if (matchingOutcome) {
            avgOdds += moneylineToProbability(matchingOutcome.price);
            bookCount++;
          }
        }
      }

      if (bookCount > 0) avgOdds = avgOdds / bookCount;

      const lineDiff = Math.abs(polyGame.yesPrice - avgOdds);
      const lineDiffPercent = (lineDiff * 100).toFixed(1);

      // Check for price movement since last poll
      const priceKey = `poly_${polyGame.conditionId}`;
      const lastPolyPrice = staticData[priceKey] || polyGame.yesPrice;
      const priceChange = Math.abs(polyGame.yesPrice - lastPolyPrice);
      staticData[priceKey] = polyGame.yesPrice;

      matches.push({
        question: polyGame.question,
        teamName: polyGame.teamName,
        slug: polyGame.slug,
        polyPrice: polyGame.yesPrice.toFixed(3),
        bookOdds: avgOdds.toFixed(3),
        lineDiff: lineDiffPercent,
        priceChange: priceChange.toFixed(3),
        priceDirection: polyGame.yesPrice > lastPolyPrice ? 'UP' : polyGame.yesPrice < lastPolyPrice ? 'DOWN' : 'FLAT',
        gameInfo: `${awayTeam} @ ${homeTeam}`,
        commenceTime: sportsGame.commence_time || ''
      });
    }
  }
}

// Flag significant moves: >3% line diff OR >5 cent Polymarket price change
const significantMoves = matches.filter(m =>
  Number(m.lineDiff) > 3 || Number(m.priceChange) > 0.05
);

if (significantMoves.length === 0) {
  return [{ json: { _noMoves: true } }];
}

let message = 'Game Day Alerts:\n\n';
for (const m of significantMoves) {
  message += `${m.gameInfo}\n`;
  message += `  Polymarket: ${m.polyPrice} | Books: ${m.bookOdds} | Diff: ${m.lineDiff}%\n`;
  if (Number(m.priceChange) > 0.05) {
    message += `  Price moved ${m.priceDirection} $${m.priceChange}\n`;
  }
  message += `  https://polymarket.com/event/${m.slug}\n\n`;
}
message += `${significantMoves.length} significant move(s) detected.`;

return [{
  json: {
    message,
    moves: significantMoves,
    moveCount: significantMoves.length,
    _noMoves: false
  }
}];

// Combine odds comparison with injury/news data, format final alert
const newsRaw = $input.first().json;
const moveData = $('Compare Odds & Detect Moves').first().json;

// If no moves were found, pass through
if (moveData._noMoves) {
  return [{ json: { _noMoves: true } }];
}

// Extract relevant news headlines
let newsItems = [];
try {
  const articles = newsRaw.articles || [];
  newsItems = articles.slice(0, 5).map(a => a.headline || a.title || '').filter(Boolean);
} catch(e) {
  // ESPN API may not return expected format
}

let message = moveData.message;
if (newsItems.length > 0) {
  message += '\n---\nRecent News:\n';
  for (const headline of newsItems) {
    message += `  - ${headline}\n`;
  }
}

return [{
  json: {
    message,
    moveCount: moveData.moveCount,
    _noMoves: false
  }
}];
